function initOrderCompleteTracking(){var e=document.getElementById("orderCompleteData");if(e){if("true"===e.dataset.loadGa){for(var t=JSON.parse(e.dataset.items||"[]"),r=[],a=0;a<t.length;a++)r.push({item_id:t[a].id,item_name:t[a].name,item_variant:t[a].variant,price:t[a].price,quantity:t[a].quantity});try{_ryshinChecker.FireEvent("onPurchase",{orderId:e.dataset.orderId,price:parseFloat(e.dataset.sumPrice),shipping:parseFloat(e.dataset.shipFee),items:r})}catch(e){}}var o=JSON.parse(e.dataset.productIds||"[]");"undefined"!=typeof LocalStorageHelper&&LocalStorageHelper.LogPurchased(o);var i=JSON.parse(e.dataset.categoryIds||"[]");if("undefined"!=typeof LocalStorageHelper)for(a=0;a<i.length;a++)LocalStorageHelper.LogCategory(i[a],!1,!1,!0,!1);try{localStorage.setItem("_suggestForceRefresh","1")}catch(e){}Site.BindingSelectAutoSubmit()}}function initVoucher(){var e=document.querySelector("[data-generate-barcode]");e&&new QRCode(e,{text:e.dataset.generateBarcode,width:64,height:64,colorDark:"#000000",colorLight:"#ffffff",correctLevel:QRCode.CorrectLevel.L})}document.addEventListener("DOMContentLoaded",function(){initVoucher(),initOrderCompleteTracking()});